import React, { useState, useEffect, useCallback } from "react";
import api from "../../utils/api";
import { jsxDEV as _jsxDEV, Fragment as _Fragment } from "react/jsx-dev-runtime";
const HOSPITAL_NAME = "PearlSmile Dental Hospital";

// ---- Status config ------------------------------------------
const STATUS_CONFIG = {
  pending: {
    label: "Pending",
    color: "#f59e0b",
    bg: "#fffbeb"
  },
  confirmed: {
    label: "Confirmed",
    color: "#2563eb",
    bg: "#eff6ff"
  },
  completed: {
    label: "Completed",
    color: "#16a34a",
    bg: "#f0fdf4"
  },
  cancelled: {
    label: "Cancelled",
    color: "#dc2626",
    bg: "#fef2f2"
  }
};

// ---- Date helpers -------------------------------------------
function toDateStr(d) {
  return d ? d.trim() : "";
}
function todayStr() {
  const d = new Date();
  const yy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");
  return `${yy}-${mm}-${dd}`;
}
function friendlyDate(dateStr) {
  if (!dateStr) return "--";
  const parts = dateStr.split("-");
  if (parts.length === 3) {
    const d = new Date(dateStr + "T00:00:00");
    if (!isNaN(d)) return d.toLocaleDateString("en-IN", {
      weekday: "short",
      day: "numeric",
      month: "short",
      year: "numeric"
    });
  }
  return dateStr;
}
function isToday(dateStr) {
  return toDateStr(dateStr) === todayStr();
}
function isPast(dateStr) {
  return toDateStr(dateStr) < todayStr();
}
function isUpcoming(dateStr) {
  return toDateStr(dateStr) > todayStr();
}

// ---- WhatsApp helpers ---------------------------------------
function waNumber(phone) {
  const num = phone.replace(/\D/g, "");
  return num.startsWith("91") ? num : "91" + num;
}
function waLink(phone) {
  return `https://wa.me/${waNumber(phone)}`;
}
function buildWaConfirmUrl(appt) {
  const msg = `Hello ${appt.name}!\n\n` + `Your appointment at *${HOSPITAL_NAME}* has been *Confirmed*.\n\n` + `Date    : ${friendlyDate(appt.date)}\n` + `Time    : ${appt.time || "As scheduled"}\n` + `Service : ${appt.service}\n\n` + `Please arrive 10 minutes early. We look forward to seeing you!\n\n` + `-- ${HOSPITAL_NAME}`;
  return `https://wa.me/${waNumber(appt.phone)}?text=${encodeURIComponent(msg)}`;
}
function buildWaCancelUrl(appt) {
